(function(){'use strict';if(typeof window==='undefined'){return;}
function showToast(message){const dlg=document.querySelector('.md-dialog');if(dlg){const msg=dlg.querySelector('.md-dialog__inner');if(msg)msg.textContent=message;dlg.classList.add('md-dialog--active');setTimeout(function(){dlg.classList.remove('md-dialog--active');},2000);}}
function sendAnalytics(actionId){if(typeof window.gtag==='function'){try{window.gtag('event','ai_file_action',{event_category:'engagement',event_label:actionId,});}catch(e){}}}
async function copyToClipboard(text){try{await navigator.clipboard.writeText(text);return true;}catch(error){let copied=false;const textarea=document.createElement('textarea');textarea.value=text;textarea.style.position='fixed';textarea.style.opacity='0';document.body.appendChild(textarea);textarea.select();try{copied=document.execCommand('copy');}catch(fallbackError){console.error('Copy fallback failed',fallbackError);}
document.body.removeChild(textarea);if(!copied){throw error;}
return true;}}
async function handleCopy(button){const url=button.dataset.url;if(!url)return;try{const response=await fetch(url,{credentials:'omit'});if(!response.ok)throw new Error(`HTTP ${response.status}`);const text=await response.text();await copyToClipboard(text);showToast('Content copied to clipboard!');}catch(error){console.error('Copy error:',error);showToast('Failed to copy content');}}
async function handleDownload(linkElement){const originalHref=linkElement.href;linkElement.dataset.downloading='true';try{const response=await fetch(originalHref,{credentials:'omit'});if(!response.ok)throw new Error(`HTTP ${response.status}`);const blob=await response.blob();const objectUrl=URL.createObjectURL(blob);linkElement.href=objectUrl;linkElement.click();setTimeout(function(){URL.revokeObjectURL(objectUrl);},100);showToast('Download started');}catch(error){console.error('Download error:',error);showToast('Failed to download file');}finally{linkElement.href=originalHref;delete linkElement.dataset.downloading;}}
function closeDropdown(menu){if(!menu)return;menu.classList.remove('show');const trigger=menu.parentElement.querySelector('.ai-file-actions-trigger',);if(trigger){trigger.classList.remove('active');trigger.setAttribute('aria-expanded','false');}}
function closeAllDropdowns(except){document.querySelectorAll('.ai-file-actions-menu.show').forEach((d)=>{if(d!==except)closeDropdown(d);});}
document.addEventListener('click',function(event){const toggleBtn=event.target.closest('.ai-file-actions-trigger');if(toggleBtn){event.preventDefault();event.stopPropagation();closeAllDropdowns(toggleBtn.nextElementSibling);const dropdown=toggleBtn.nextElementSibling;if(dropdown){dropdown.classList.toggle('show');const isExpanded=dropdown.classList.contains('show');toggleBtn.setAttribute('aria-expanded',isExpanded);toggleBtn.classList.toggle('active',isExpanded);if(isExpanded){const first=dropdown.querySelector('.ai-file-actions-item');if(first)first.focus();}}
return;}
const copyBtn=event.target.closest('.ai-file-actions-copy');if(copyBtn){event.preventDefault();sendAnalytics(copyBtn.dataset.action||'copy-markdown');handleCopy(copyBtn);return;}
const item=event.target.closest('.ai-file-actions-item');if(item){closeDropdown(item.closest('.ai-file-actions-menu'));sendAnalytics(item.dataset.actionId||'');if(item.hasAttribute('download')){if(!item.dataset.downloading){event.preventDefault();handleDownload(item);}
return;}
if(item.tagName==='A'){return;}
if(item.dataset.actionType==='clipboard'){event.preventDefault();handleCopy(item);}
return;}
if(!event.target.closest('.ai-file-actions-container')){closeAllDropdowns();}});document.addEventListener('keydown',function(event){const menu=document.querySelector('.ai-file-actions-menu.show');if(!menu)return;const items=Array.from(menu.querySelectorAll('.ai-file-actions-item'));if(!items.length)return;const currentIndex=items.findIndex((item)=>item===document.activeElement,);switch(event.key){case'ArrowDown':event.preventDefault();items[currentIndex===-1?0:(currentIndex+1)%items.length].focus();break;case'ArrowUp':event.preventDefault();items[currentIndex===-1?items.length-1:(currentIndex-1+items.length)%items.length].focus();break;case'Enter':case' ':event.preventDefault();if(currentIndex>=0)items[currentIndex].click();break;case'Escape':event.preventDefault();closeDropdown(menu);const trigger=menu.parentElement.querySelector('.ai-file-actions-trigger',);if(trigger)trigger.focus();break;}});})();